import React, { createContext, useState, useContext, useEffect, useMemo } from 'react';
import { ThemeProvider, createTheme, Theme, responsiveFontSizes } from '@mui/material/styles';
import { CssBaseline, alpha } from '@mui/material';
import { useFirebase } from './FirebaseContext';
import { PaletteMode } from '@mui/material';

// Типы темы
type ThemeMode = 'light' | 'dark';

// Контекст
interface ThemeContextType {
  mode: PaletteMode;
  toggleTheme: () => void;
}

// Создаем контекст
const ThemeContext = createContext<ThemeContextType>({
  mode: 'light',
  toggleTheme: () => {},
});

// Хук для использования контекста темы
export const useThemeContext = () => useContext(ThemeContext);

// Свойства провайдера темы
interface ThemeProviderProps {
  children: React.ReactNode;
}

// ThemeProvider обертка для доступа к Firebase данным
export const AppThemeProvider: React.FC<ThemeProviderProps> = ({ children }) => {
  // Создаем FirebaseContext stub для избежания циклической зависимости
  const firebaseStub = {
    appSettings: {
      primaryColor: localStorage.getItem('primaryColor') || '#2196F3',
      secondaryColor: localStorage.getItem('secondaryColor') || '#9C27B0'
    },
    companies: [],
    raffles: [],
    activeCompany: null,
    carFeatures: [],
    loading: false,
    error: null,
    setActiveCompany: () => {},
    refreshData: async () => {},
    addCompany: async () => ({ id: '' }),
    editCompany: async () => false,
    removeCompany: async () => false,
    addRaffle: async () => ({ id: '' }),
    editRaffle: async () => false,
    removeRaffle: async () => false,
    updateCarSpecs: async () => false,
    updateSettings: async (settings: { primaryColor?: string; secondaryColor?: string; [key: string]: any }) => {
      if (settings.primaryColor) localStorage.setItem('primaryColor', settings.primaryColor);
      if (settings.secondaryColor) localStorage.setItem('secondaryColor', settings.secondaryColor);
      return true;
    }
  };

  return (
    <ThemeContext.Provider value={{ 
      mode: localStorage.getItem('themeMode') as PaletteMode || 'light',
      toggleTheme: () => {},
    }}>
      <InnerThemeProvider firebaseData={firebaseStub}>
        {children}
      </InnerThemeProvider>
    </ThemeContext.Provider>
  );
};

// Внутренний провайдер темы, принимающий данные Firebase напрямую
interface InnerThemeProviderProps extends ThemeProviderProps {
  firebaseData: any;
}

const InnerThemeProvider: React.FC<InnerThemeProviderProps> = ({ children, firebaseData }) => {
  // Получаем сохраненную тему из localStorage
  const savedMode = localStorage.getItem('themeMode') as PaletteMode | null;
  const prefersDarkMode = window.matchMedia('(prefers-color-scheme: dark)').matches;
  
  // Если есть сохраненная тема, используем ее, иначе определяем по системным настройкам
  const [mode, setMode] = useState<PaletteMode>(
    savedMode || (prefersDarkMode ? 'dark' : 'light')
  );

  // Функция переключения темы
  const toggleTheme = () => {
    setMode((prevMode) => {
      const newMode = prevMode === 'light' ? 'dark' : 'light';
      localStorage.setItem('themeMode', newMode);
      return newMode;
    });
  };

  // Следим за изменениями системной темы
  useEffect(() => {
    const mediaQuery = window.matchMedia('(prefers-color-scheme: dark)');
    const handleChange = (e: MediaQueryListEvent) => {
      if (!localStorage.getItem('themeMode')) {
        setMode(e.matches ? 'dark' : 'light');
      }
    };
    
    mediaQuery.addEventListener('change', handleChange);
    return () => mediaQuery.removeEventListener('change', handleChange);
  }, []);

  // Создание темы с улучшенной палитрой для премиум-дизайна
  const theme = useMemo(() => {
    const getDesignTokens = (mode: PaletteMode): Theme => {
      return createTheme({
        palette: {
          mode,
          ...(mode === 'light'
            ? {
                // Палитра светлой темы (более премиальная)
                primary: {
                  main: '#0052CC', // Более глубокий синий цвет для премиальности
                  light: '#4C9AFF',
                  dark: '#0747A6',
                  contrastText: '#FFFFFF',
                },
                secondary: {
                  main: '#172B4D',
                  light: '#505F79',
                  dark: '#091E42',
                  contrastText: '#FFFFFF',
                },
                error: {
                  main: '#DE350B',
                  light: '#FF5630',
                  dark: '#BF2600',
                },
                warning: {
                  main: '#FF8B00',
                  light: '#FFB400',
                  dark: '#CC5F00',
                },
                info: {
                  main: '#0065FF',
                  light: '#4C9AFF',
                  dark: '#0052CC',
                },
                success: {
                  main: '#008952',
                  light: '#36B37E',
                  dark: '#006644',
                },
                background: {
                  default: '#F8F9FD', // Чуть голубоватый оттенок для стильного фона
                  paper: '#FFFFFF',
                },
                text: {
                  primary: '#172B4D',
                  secondary: '#5E6C84',
                },
                divider: 'rgba(9, 30, 66, 0.08)',
              }
            : {
                // Палитра темной темы (более премиальная)
                primary: {
                  main: '#4C9AFF',
                  light: '#79B8FF',
                  dark: '#2684FF',
                  contrastText: '#FFFFFF',
                },
                secondary: {
                  main: '#A1BDD9',
                  light: '#C1DFFF',
                  dark: '#89A2BF',
                  contrastText: '#121822',
                },
                error: {
                  main: '#FF5630',
                  light: '#FF8F73',
                  dark: '#DE350B',
                },
                warning: {
                  main: '#FF991F',
                  light: '#FFBDAD',
                  dark: '#FF8B00',
                },
                info: {
                  main: '#4C9AFF',
                  light: '#79B8FF',
                  dark: '#2684FF',
                },
                success: {
                  main: '#36B37E',
                  light: '#57D9A3',
                  dark: '#00875A',
                },
                background: {
                  default: '#0F1626', // Глубокий тёмно-синий для премиум ощущения
                  paper: '#1A202C',
                },
                text: {
                  primary: '#E2E8F0',
                  secondary: '#A0AEC0',
                },
                divider: 'rgba(255, 255, 255, 0.08)',
              }),
        },
        // Обновленные угловые радиусы для более современного вида
        shape: {
          borderRadius: 12,
        },
        // Обновленная типография
        typography: {
          fontFamily: '"Inter", -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif',
          h1: {
            fontWeight: 700,
            fontSize: '2.5rem',
            letterSpacing: '-0.01562em',
          },
          h2: {
            fontWeight: 700,
            fontSize: '2rem',
            letterSpacing: '-0.00833em',
          },
          h3: {
            fontWeight: 700,
            fontSize: '1.75rem',
            letterSpacing: '0em',
          },
          h4: {
            fontWeight: 700,
            fontSize: '1.5rem',
            letterSpacing: '0.00735em',
          },
          h5: {
            fontWeight: 600,
            fontSize: '1.25rem',
            letterSpacing: '0em',
          },
          h6: {
            fontWeight: 600,
            fontSize: '1.125rem',
            letterSpacing: '0.0075em',
          },
          subtitle1: {
            fontWeight: 500,
            fontSize: '1rem',
            letterSpacing: '0.00938em',
          },
          subtitle2: {
            fontWeight: 500,
            fontSize: '0.875rem',
            letterSpacing: '0.00714em',
          },
          body1: {
            fontWeight: 400,
            fontSize: '1rem',
            letterSpacing: '0.00938em',
          },
          body2: {
            fontWeight: 400,
            fontSize: '0.875rem',
            letterSpacing: '0.01071em',
          },
          button: {
            fontWeight: 600,
            fontSize: '0.875rem',
            letterSpacing: '0.02857em',
            textTransform: 'none',
          },
        },
        // Обновленные тени для глубины и премиальности
        shadows: [
          'none',
          '0px 2px 4px rgba(0, 0, 0, 0.04), 0px 1px 2px rgba(0, 0, 0, 0.08)',
          '0px 4px 8px rgba(0, 0, 0, 0.06), 0px 2px 4px rgba(0, 0, 0, 0.1)',
          '0px 8px 16px rgba(0, 0, 0, 0.08), 0px 4px 8px rgba(0, 0, 0, 0.12)',
          '0px 12px 24px rgba(0, 0, 0, 0.1), 0px 6px 12px rgba(0, 0, 0, 0.15)',
          '0px 16px 32px rgba(0, 0, 0, 0.12), 0px 8px 16px rgba(0, 0, 0, 0.16)',
          ...Array(19).fill('none'),
          '0px 20px 40px rgba(0, 0, 0, 0.15), 0px 12px 24px rgba(0, 0, 0, 0.2)', // elevation 24 для дополнительной глубины
        ],
        // Компоненты с улучшенными стилями
        components: {
          MuiButton: {
            styleOverrides: {
              root: {
                borderRadius: 12,
                padding: '10px 20px',
                fontWeight: 600,
                textTransform: 'none',
                boxShadow: mode === 'light' 
                  ? '0px 4px 12px rgba(0, 0, 0, 0.08), 0px 2px 6px rgba(0, 0, 0, 0.04)'
                  : '0px 4px 12px rgba(0, 0, 0, 0.3)',
              },
              contained: {
                '&:hover': {
                  boxShadow: mode === 'light'
                    ? '0px 8px 16px rgba(0, 0, 0, 0.1), 0px 4px 8px rgba(0, 0, 0, 0.06)'
                    : '0px 8px 16px rgba(0, 0, 0, 0.4)',
                },
              },
            },
          },
          MuiCard: {
            styleOverrides: {
              root: {
                borderRadius: 16,
                overflow: 'hidden',
                boxShadow: mode === 'light'
                  ? '0px 8px 20px rgba(0, 0, 0, 0.06), 0px 4px 10px rgba(0, 0, 0, 0.04)'
                  : '0px 8px 20px rgba(0, 0, 0, 0.15)',
              },
            },
          },
          MuiPaper: {
            styleOverrides: {
              root: {
                borderRadius: 16,
              },
            },
          },
          MuiChip: {
            styleOverrides: {
              root: {
                fontWeight: 500,
                borderRadius: 8,
              },
            },
          },
          MuiAvatar: {
            styleOverrides: {
              root: {
                borderRadius: 12,
              },
            },
          },
          MuiAppBar: {
            styleOverrides: {
              root: {
                boxShadow: mode === 'light'
                  ? '0px 2px 8px rgba(0, 0, 0, 0.05)'
                  : '0px 2px 8px rgba(0, 0, 0, 0.2)',
              },
            },
          },
          MuiInputBase: {
            styleOverrides: {
              root: {
                borderRadius: 12,
              },
            },
          },
          MuiLinearProgress: {
            styleOverrides: {
              root: {
                borderRadius: 8,
                height: 8,
                backgroundColor: mode === 'light' 
                  ? 'rgba(0, 0, 0, 0.05)' 
                  : 'rgba(255, 255, 255, 0.08)',
              },
            },
          },
        },
      });
    };

    const baseTheme = getDesignTokens(mode);
    return responsiveFontSizes(baseTheme);
  }, [mode]);
  
  // Мемоизируем значение контекста
  const contextValue = useMemo(
    () => ({
      mode,
      toggleTheme,
    }),
    [mode]
  );

  return (
    <ThemeContext.Provider value={contextValue}>
      <ThemeProvider theme={theme}>
        <CssBaseline />
        {children}
      </ThemeProvider>
    </ThemeContext.Provider>
  );
};
